import { NewMetricOptions } from './client';
import { Tags, Emitter } from './metric';
/** global metric 需要兼容多版本，所以控制一下暴露的 api */
interface GlobalMetric<TagKeys extends string = string> {
    close(): Promise<void>;
    withTags(tags?: Tags<TagKeys | (string & {})>): Emitter;
}
/**
 * 默认的 newMetric 方法，给到基础库使用，省去每个基础库都重新 new 个 client
 * 注意！！该方法不能调用过多，创建的 metric 会被缓存（ 调用 metric.close 可以释放 ）
 */
export declare function newMetric<TagKeys extends string = string>(metricName: string, options: NewMetricOptions<TagKeys>): GlobalMetric<TagKeys>;
export {};
